namespace CourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace CourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Description = "Pure and applied mathematics including statistics." },
        new() { Id = 3, Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Description = "Literature, writing, and language studies." },
        new() { Id = 5, Name = "History", Description = "Study of past events and human civilization." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Covers variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 2, CourseCode = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. Previously worked at Google Research.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 3, CourseCode = "CS301", Title = "Database Systems", Description = "Design and implementation of relational databases, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez spent a decade at Oracle before joining academia. Her research focuses on distributed database systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
        new() { Id = 4, CourseCode = "CS401", Title = "Machine Learning", Description = "Introduction to supervised and unsupervised learning, neural networks, and practical applications.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 5, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with over 20 years of experience teaching undergraduate mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
        new() { Id = 6, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research interests include abstract algebra and its applications in cryptography.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
        new() { Id = 7, CourseCode = "MATH301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with over 20 years of experience teaching undergraduate mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
        new() { Id = 8, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed 8:00–9:15 AM, Fri Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist who has contributed to research at CERN and Fermilab.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
        new() { Id = 9, CourseCode = "PHYS201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist who has contributed to research at CERN and Fermilab.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
        new() { Id = 10, CourseCode = "ENG101", Title = "College Writing", Description = "Develop skills in academic writing, argumentation, research methods, and critical reading.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Linda Hayes", InstructorBio = "Prof. Hayes is a published author and writing consultant with expertise in rhetoric and composition.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 11, CourseCode = "ENG201", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Michael Grant", InstructorBio = "Dr. Grant is a specialist in 20th-century American fiction and has authored three books on the subject.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 12, CourseCode = "HIST101", Title = "World History to 1500", Description = "Survey of major civilizations, cultures, and events from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen specializes in ancient and medieval history with a focus on cross-cultural exchange along trade routes.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        new() { Id = 13, CourseCode = "HIST201", Title = "Modern World History", Description = "Political, economic, and social developments from the Renaissance to the present day.", Credits = 3, Schedule = "Tue/Thu 3:30–4:45 PM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen specializes in ancient and medieval history with a focus on cross-cultural exchange along trade routes.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.CourseCode).ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

