arguments.file_text:
@page "/courses"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @courses.Count course(s)</p>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@inject CourseCatalog.Services.CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <PageTitle>@course.CourseCode — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@course.DepartmentId">@course.DepartmentName</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p><span class="badge bg-secondary">@course.Schedule</span></p>

            <h4 class="mt-4">Credits</h4>
            <p><strong>@course.Credits</strong> credit hours</p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <a href="enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private CourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@(CatalogService.GetCourse(Model.CourseId)?.Title ?? "the selected course")</strong>
            has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation email at your university address shortly.</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
